def _index_by_id(items):
    return {item["id"]: item for item in items}


CATEGORY_BY_ID = _index_by_id(DATA["categories"])
PRODUCT_BY_ID = _index_by_id(DATA["products"])
REVIEW_BY_ID = _index_by_id(DATA["reviews"])


def _product_reviews(product_id):
    return [r for r in DATA["reviews"] if r["product_id"] == product_id]


def _category_products(category_id):
    return [p for p in DATA["products"] if p["category_id"] == category_id]


def _avg_rating(product_id):
    rs = _product_reviews(product_id)
    if not rs:
        return None
    return sum(r["rating"] for r in rs) / float(len(rs))


