class Query(ObjectType):
    product = Field(ProductType, id=ID(), sku=String())
    products = List(
        ProductType,
        category_id=ID(),
        category_slug=String(),
        search=String(),
        tag=String(),
        in_stock=Boolean(),
        limit=Int(default_value=20),
        offset=Int(default_value=0),
    )

    category = Field(CategoryType, id=ID(), slug=String())
    categories = List(CategoryType, limit=Int(default_value=50), offset=Int(default_value=0))

    review = Field(ReviewType, id=ID(required=True))
    reviews = List(ReviewType, product_id=ID(), user_id=ID(), limit=Int(default_value=20), offset=Int(default_value=0))

    def resolve_product(self, info, id=None, sku=None):
        if id:
            return PRODUCT_BY_ID.get(id)
        if sku:
            for p in DATA["products"]:
                if p["sku"] == sku:
                    return p
        return None

    def resolve_products(
        self,
        info,
        category_id=None,
        category_slug=None,
        search=None,
        tag=None,
        in_stock=None,
        limit=20,
        offset=0,
    ):
        items = list(DATA["products"])

        if category_slug and not category_id:
            for c in DATA["categories"]:
                if c["slug"] == category_slug:
                    category_id = c["id"]
                    break

        if category_id:
            items = [p for p in items if p["category_id"] == category_id]

        if search:
            s = search.strip().lower()
            items = [
                p
                for p in items
                if s in (p.get("name") or "").lower()
                or s in (p.get("description") or "").lower()
                or s in (p.get("sku") or "").lower()
            ]

        if tag:
            t = tag.strip().lower()
            items = [p for p in items if any((x or "").lower() == t for x in (p.get("tags") or []))]

        if in_stock is not None:
            items = [p for p in items if bool(p.get("in_stock")) == bool(in_stock)]

        return items[offset : offset + limit]

    def resolve_category(self, info, id=None, slug=None):
        if id:
            return CATEGORY_BY_ID.get(id)
        if slug:
            for c in DATA["categories"]:
                if c["slug"] == slug:
                    return c
        return None

    def resolve_categories(self, info, limit=50, offset=0):
        items = list(DATA["categories"])
        return items[offset : offset + limit]

    def resolve_review(self, info, id):
        return REVIEW_BY_ID.get(id)

    def resolve_reviews(self, info, product_id=None, user_id=None, limit=20, offset=0):
        items = list(DATA["reviews"])
        if product_id:
            items = [r for r in items if r["product_id"] == product_id]
        if user_id:
            items = [r for r in items if r["user_id"] == user_id]
        return items[offset : offset + limit]


schema = graphene.Schema(query=Query, auto_camelcase=False)


